1	// WORKSTATE 상태 전이의 유일한 writer.
2	// prepare: 전이 계획(envelope+candidate)을 outputs/state-transition/에 기록한다.
3	// apply: reconciliation-먼저, 멱등 결속, rollback, FATAL 분류 포함 전이를 실행한다.
4	using System.Globalization;
5	using System.Security.Cryptography;
6	using System.Text;
7	using System.Text.Encodings.Web;
8	using System.Text.Json;
9	using System.Text.Json.Nodes;
10	using System.Text.RegularExpressions;
11	
12	internal static class StateApplierCli
13	{
14	    private static readonly JsonSerializerOptions WriteOptions = new()
15	    {
16	        WriteIndented = true,
17	        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
18	    };
19	
20	    private static readonly HashSet<string> ValidStatuses = new(StringComparer.OrdinalIgnoreCase)
21	    {
22	        "waiting", "in_progress", "verifying", "completed", "blocked",
23	    };
24	
25	    // 허용 전이 화이트리스트 — 이 표 밖의 전이는 전부 거부(completed는 terminal).
26	    private static readonly Dictionary<string, HashSet<string>> AllowedTransitions = new(StringComparer.OrdinalIgnoreCase)
27	    {
28	        ["waiting"] = new(StringComparer.OrdinalIgnoreCase) { "in_progress", "blocked" },
29	        ["in_progress"] = new(StringComparer.OrdinalIgnoreCase) { "verifying", "blocked", "waiting" },
30	        ["verifying"] = new(StringComparer.OrdinalIgnoreCase) { "completed", "in_progress", "blocked" },
31	        ["blocked"] = new(StringComparer.OrdinalIgnoreCase) { "waiting", "in_progress", "verifying" },
32	        ["completed"] = new(StringComparer.OrdinalIgnoreCase) { },
33	    };
34	
35	    // nextActions 필수 status 목록(completed 제외).
36	    private static readonly HashSet<string> NextActionsRequired = new(StringComparer.OrdinalIgnoreCase)
37	    {
38	        "waiting", "in_progress", "verifying", "blocked",
39	    };
40	
41	    // high-risk transitionKind — receipt ledger 부재로 이번 WP에서 fail-closed.
42	    private static readonly HashSet<string> HighRiskKinds = new(StringComparer.OrdinalIgnoreCase)
43	    {
44	        "PHASE_CHANGE", "RECOVERY", "REPLAY",
45	    };
46	
47	    // 파싱된 envelope 데이터 레코드.
48	    private record EnvelopeData(
49	        int SchemaVersion,
50	        string TransitionKind,
51	        string TransitionId,
52	        string ExpectedPreStateSha256,
53	        string RequestPath,
54	        string RequestSha256,
55	        string EffectiveAt,
56	        string ExpectedPostStateSha256,
57	        string? TransitionContractSha256,
58	        string CandidatePath);
59	
60	    // prepare 부속 명령 옵션.
61	    private record PrepareOptions(string TransitionId, string RequestPath, string? Root, bool DryRun);
62	
63	    // apply 부속 명령 옵션.
64	    private record ApplyOptions(string EnvelopePath, string? VerdictPath, string? Root, bool DryRun);
65	
66	    // 이전 단일-샷 CLI 옵션 (backward compat).
67	    private record LegacyOptions(
68	        string TransitionId,
69	        string ExpectedSha256,
70	        string RequestPath,
71	        string? VerdictPath,
72	        string? HumanDecisionPath,
73	        string? Root,
74	        bool DryRun);
75	
76	    // state-transition 진입점. prepare/apply/legacy를 args[1]로 분기한다.
77	    internal static int Run(string[] args)
78	    {
79	        var sub = args.Length > 1 ? args[1] : "";
80	        if (string.Equals(sub, "prepare", StringComparison.OrdinalIgnoreCase))
81	            return RunPrepare(args);
82	        if (string.Equals(sub, "apply", StringComparison.OrdinalIgnoreCase))
83	            return RunApply(args);
84	        return RunLegacy(args);
85	    }
86	
87	    // prepare: WORKSTATE를 읽어 결정적 candidate를 계산하고 envelope+candidate를 출력 디렉터리에 기록한다.
88	    private static int RunPrepare(string[] args)
89	    {
90	        var opts = ParsePrepareArgs(args);
91	        if (opts is null)
92	        {
93	            Console.Error.WriteLine("{\"error\":\"prepare에는 --transition-id, --request 가 필요합니다\"}");
94	            return 2;
95	        }
96	        try
97	        {
98	            var root = string.IsNullOrWhiteSpace(opts.Root) ? GitTools.FindRepoRoot() : opts.Root;
99	            var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
100	            if (!File.Exists(workstatePath)) { WriteError("WORKSTATE.json not found"); return 2; }
101	
102	            var rawWorkstate = File.ReadAllText(workstatePath, new UTF8Encoding(false));
103	            var workstate = JsonNode.Parse(rawWorkstate)?.AsObject();
104	            if (workstate is null) { WriteError("WORKSTATE.json is not a valid JSON object"); return 2; }
105	
106	            if (!File.Exists(opts.RequestPath)) { WriteError($"request file not found: {opts.RequestPath}"); return 2; }
107	            var rawRequest = File.ReadAllText(opts.RequestPath, new UTF8Encoding(false));
108	            var request = JsonNode.Parse(rawRequest)?.AsObject();
109	            if (request is null) { WriteError("request JSON must be a JSON object"); return 2; }
110	
111	            // 해시 계산 + effectiveAt 발급 (NORMAL은 prepare가 현재 UTC를 발급, 외부 플래그 없음).
112	            var preStateSha256 = ComputeSha256(rawWorkstate);
113	            var requestSha256 = ComputeSha256(rawRequest);
114	            var effectiveAt = DateTime.UtcNow.ToString("o");
115	
116	            // 결정적 candidate 계산 — UtcNow 호출 없이 effectiveAt을 파라미터로 받는다.
117	            var candidate = BuildCandidate(workstate, request, opts.TransitionId, effectiveAt);
118	            var candidateBytes = Encoding.UTF8.GetBytes(candidate.ToJsonString(WriteOptions));
119	            var postStateSha256 = Convert.ToHexString(SHA256.HashData(candidateBytes)).ToLowerInvariant();
120	            var contractHash = ComputeContractHash(
121	                opts.TransitionId, "NORMAL", requestSha256, preStateSha256, postStateSha256, effectiveAt);
122	
123	            if (opts.DryRun)
124	            {
125	                Console.WriteLine(new JsonObject
126	                {
127	                    ["ok"] = true, ["dryRun"] = true,
128	                    ["transitionId"] = opts.TransitionId,
129	                    ["preStateSha256"] = preStateSha256,
130	                    ["expectedPostStateSha256"] = postStateSha256,
131	                    ["transitionContractSha256"] = contractHash,
132	                }.ToJsonString(WriteOptions));
133	                return 0;
134	            }
135	
136	            return WritePrepareOutput(root, opts, preStateSha256, requestSha256, postStateSha256, contractHash, candidateBytes, effectiveAt);
137	        }
138	        catch (Exception ex)
139	        {
140	            Console.Error.WriteLine($"{{\"error\":\"state-transition prepare 실패: {ex.Message}\"}}");
141	            return 2;
142	        }
143	    }
144	
145	    // envelope+candidate 파일을 outputs/state-transition/에 기록하고 결과를 출력한다.
146	    private static int WritePrepareOutput(
147	        string root, PrepareOptions opts, string preStateSha256, string requestSha256,
148	        string postStateSha256, string contractHash, byte[] candidateBytes, string effectiveAt)
149	    {
150	        var outDir = Path.Combine(root, "outputs", "state-transition");
151	        Directory.CreateDirectory(outDir);
152	        var safeTid = Regex.Replace(opts.TransitionId, @"[^\w\-]", "_");
153	
154	        // candidate 파일 기록 — evidence용. apply는 이 파일을 canonical write에 쓰지 않는다.
155	        var candidatePath = Path.Combine(outDir, $"{safeTid}.candidate.json");
156	        File.WriteAllBytes(candidatePath, candidateBytes);
157	
158	        var envelope = new JsonObject
159	        {
160	            ["schemaVersion"] = 1,
161	            ["transitionKind"] = "NORMAL",
162	            ["transitionId"] = opts.TransitionId,
163	            ["expectedPreStateSha256"] = preStateSha256,
164	            ["requestPath"] = opts.RequestPath,
165	            ["requestSha256"] = requestSha256,
166	            ["effectiveAt"] = effectiveAt,
167	            ["expectedPostStateSha256"] = postStateSha256,
168	            ["transitionContractSha256"] = contractHash,
169	            ["candidatePath"] = candidatePath,
170	        };
171	
172	        var envelopePath = Path.Combine(outDir, $"{safeTid}.envelope.json");
173	        File.WriteAllText(envelopePath, envelope.ToJsonString(WriteOptions), new UTF8Encoding(false));
174	
175	        Console.WriteLine(new JsonObject
176	        {
177	            ["ok"] = true,
178	            ["transitionId"] = opts.TransitionId,
179	            ["envelopePath"] = envelopePath,
180	            ["candidatePath"] = candidatePath,
181	            ["preStateSha256"] = preStateSha256,
182	            ["expectedPostStateSha256"] = postStateSha256,
183	            ["transitionContractSha256"] = contractHash,
184	        }.ToJsonString(WriteOptions));
185	        return 0;
186	    }
187	
188	    // apply: reconciliation-먼저 순서로 WORKSTATE에 전이를 적용한다. rollback + FATAL 분류 포함.
189	    private static int RunApply(string[] args)
190	    {
191	        var opts = ParseApplyArgs(args);
192	        if (opts is null)
193	        {
194	            Console.Error.WriteLine("{\"error\":\"apply에는 --envelope 이 필요합니다\"}");
195	            return 2;
196	        }
197	
198	        // Envelope 읽기 — 이 단계는 atomic write 전이므로 예외 발생 시 rollback 불필요.
199	        var envelope = ReadEnvelope(opts.EnvelopePath);
200	        if (envelope is null) return 2;
201	
202	        // high-risk transitionKind — receipt ledger 부재로 항상 fail-closed.
203	        if (HighRiskKinds.Contains(envelope.TransitionKind))
204	            return Fail(1, envelope.TransitionId, "trusted-human-receipt-required",
205	                $"transitionKind={envelope.TransitionKind}는 receipt ledger 부재로 이번 WP에서 fail-closed");
206	
207	        string root, workstatePath, logPath;
208	        bool canonicalMode;
209	        try
210	        {
211	            root = string.IsNullOrWhiteSpace(opts.Root) ? GitTools.FindRepoRoot() : opts.Root;
212	            workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
213	            logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
214	            canonicalMode = string.IsNullOrWhiteSpace(opts.Root);
215	        }
216	        catch (Exception ex)
217	        {
218	            Console.Error.WriteLine($"{{\"error\":\"root 결정 실패: {ex.Message}\"}}");
219	            return 2;
220	        }
221	
222	        if (!File.Exists(workstatePath)) { WriteError("WORKSTATE.json not found"); return 2; }
223	
224	        byte[] rawWorkstateBytes;
225	        JsonObject workstate;
226	        string rawWorkstateStr;
227	        try
228	        {
229	            rawWorkstateBytes = File.ReadAllBytes(workstatePath);
230	            rawWorkstateStr = Encoding.UTF8.GetString(rawWorkstateBytes);
231	            workstate = JsonNode.Parse(rawWorkstateStr)?.AsObject()
232	                ?? throw new InvalidOperationException("WORKSTATE.json is not a valid JSON object");
233	        }
234	        catch (Exception ex) { WriteError(ex.Message); return 2; }
235	
236	        // Step 1: request sha256 + candidate file hash 검증.
237	        var (_, request, evidenceExit) = VerifyApplyEvidence(envelope);
238	        if (evidenceExit.HasValue) return evidenceExit.Value;
239	
240	        // Step 2: reconciliation — 실패하면 일반 전이를 거부한다.
241	        // ★ 순서 정정(§1): reconciliation이 existing-transition보다 먼저여야 가짜 id 공격을 막는다.
242	        ReconciliationResult reconResult;
243	        try { reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath)); }
244	        catch (Exception ex) { WriteError($"reconciliation 실행 실패: {ex.Message}"); return 2; }
245	
246	        if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
247	        {
248	            var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
249	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply", $"reconciliation failed: {codes}");
250	        }
251	
252	        // Step 3: existing-transition 판정 (idempotent / collision / legacy-unverifiable).
253	        // ★ 순서 정정(§1): existing-transition이 pre-state hash보다 먼저여야 재시도가 산다.
254	        var existingResult = CheckExistingTransition(workstate, reconResult, envelope);
255	        if (existingResult.HasValue) return existingResult.Value;
256	
257	        // Steps 4-6: candidate 재계산 + 검증 + dry-run.
258	        var (recompCandidate, recompBytes, validateExit) =
259	            RunApplyValidatePhase(envelope, workstate, rawWorkstateStr, request!, opts.DryRun, root);
260	        if (validateExit.HasValue) return validateExit.Value;
261	
262	        // Steps 7-10: atomic write + post-apply 검사 + v2 log.
263	        return RunApplyCommitPhase(
264	            envelope, workstatePath, logPath, canonicalMode,
265	            rawWorkstateBytes, workstate, recompCandidate!, recompBytes!);
266	    }
267	
268	    // request sha256 + candidate file hash를 검증한다. 성공 시 (rawRequest, request, null) 반환.
269	    private static (string? rawRequest, JsonObject? request, int? exitCode) VerifyApplyEvidence(EnvelopeData envelope)
270	    {
271	        if (!File.Exists(envelope.RequestPath)) { WriteError($"request file not found: {envelope.RequestPath}"); return (null, null, 2); }
272	        string rawRequest;
273	        JsonObject request;
274	        try
275	        {
276	            rawRequest = File.ReadAllText(envelope.RequestPath, new UTF8Encoding(false));
277	            var actualRequestSha = ComputeSha256(rawRequest);
278	            if (!string.Equals(actualRequestSha, envelope.RequestSha256, StringComparison.OrdinalIgnoreCase))
279	                return (null, null, Fail(1, envelope.TransitionId, "request-sha256-mismatch",
280	                    "request file changed since prepare"));
281	            request = JsonNode.Parse(rawRequest)?.AsObject()
282	                ?? throw new InvalidOperationException("request JSON must be a JSON object");
283	        }
284	        catch (Exception ex) { WriteError(ex.Message); return (null, null, 2); }
285	
286	        if (!File.Exists(envelope.CandidatePath)) { WriteError($"candidate file not found: {envelope.CandidatePath}"); return (null, null, 2); }
287	        try
288	        {
289	            var candidateFileHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(envelope.CandidatePath))).ToLowerInvariant();
290	            if (!string.Equals(candidateFileHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
291	                return (null, null, Fail(1, envelope.TransitionId, "candidate-tampered",
292	                    "candidate file hash differs from envelope.expectedPostStateSha256 — evidence may have been tampered"));
293	        }
294	        catch (Exception ex) { WriteError($"candidate 파일 읽기 실패: {ex.Message}"); return (null, null, 2); }
295	
296	        return (rawRequest, request, null);
297	    }
298	
299	    // Steps 4-6: candidate 재계산 + hash 검증 + pre-state hash + request 검증 + dry-run 처리.
300	    private static (JsonObject? candidate, byte[]? bytes, int? earlyExit) RunApplyValidatePhase(
301	        EnvelopeData envelope, JsonObject workstate, string rawWorkstateStr,
302	        JsonObject request, bool dryRun, string root)
303	    {
304	        JsonObject recomputedCandidate;
305	        byte[] recomputedBytes;
306	        try
307	        {
308	            // Step 4: 메모리에서 candidate 재계산 + hash 검증 (TOCTOU 방어).
309	            recomputedCandidate = BuildCandidate(workstate, request, envelope.TransitionId, envelope.EffectiveAt);
310	            recomputedBytes = Encoding.UTF8.GetBytes(recomputedCandidate.ToJsonString(WriteOptions));
311	            var recomputedHash = Convert.ToHexString(SHA256.HashData(recomputedBytes)).ToLowerInvariant();
312	            if (!string.Equals(recomputedHash, envelope.ExpectedPostStateSha256, StringComparison.OrdinalIgnoreCase))
313	                return (null, null, Fail(1, envelope.TransitionId, "candidate-recompute-mismatch",
314	                    "recomputed candidate hash differs — WORKSTATE or request changed since prepare"));
315	        }
316	        catch (Exception ex) { WriteError($"candidate 재계산 실패: {ex.Message}"); return (null, null, 2); }
317	
318	        // Step 5: pre-state hash 검증 (미적용 ID에 한해 실행).
319	        var currentHash = ComputeSha256(rawWorkstateStr);
320	        if (!string.Equals(currentHash, envelope.ExpectedPreStateSha256, StringComparison.OrdinalIgnoreCase))
321	            return (null, null, Fail(1, envelope.TransitionId, "pre-state-hash-mismatch",
322	                $"expected={Short(envelope.ExpectedPreStateSha256)} actual={Short(currentHash)}"));
323	
324	        // Step 6: request 검증.
325	        var validErr = ValidateRequestForApply(request, envelope, workstate, root);
326	        if (validErr is not null)
327	            return (null, null, Fail(1, envelope.TransitionId, "validation-failed", validErr));
328	
329	        if (dryRun)
330	        {
331	            Console.WriteLine(new JsonObject
332	            {
333	                ["ok"] = true, ["dryRun"] = true,
334	                ["transitionId"] = envelope.TransitionId,
335	                ["previousStatus"] = workstate["status"]?.ToString(),
336	                ["newStatus"] = recomputedCandidate["status"]?.ToString(),
337	            }.ToJsonString(WriteOptions));
338	            return (null, null, 0);
339	        }
340	
341	        return (recomputedCandidate, recomputedBytes, null);
342	    }
343	
344	    // Steps 7-10: preimage 저장 → atomic write → test seam → post-apply 검사 → v2 log append.
345	    private static int RunApplyCommitPhase(
346	        EnvelopeData envelope, string workstatePath, string logPath, bool canonicalMode,
347	        byte[] rawWorkstateBytes, JsonObject workstate, JsonObject recomputedCandidate, byte[] recomputedBytes)
348	    {
349	        // Step 7: preimage 저장 — atomic replace 전에 반드시 저장해야 한다.
350	        var preimage = rawWorkstateBytes;
351	        var preimageHash = Convert.ToHexString(SHA256.HashData(preimage)).ToLowerInvariant();
352	
353	        // Step 8: atomic replace — 재계산 bytes만 사용(candidate 파일은 evidence, write source 아님).
354	        try { var t = workstatePath + ".stateapplier.tmp"; File.WriteAllBytes(t, recomputedBytes); File.Move(t, workstatePath, overwrite: true); }
355	        catch (Exception ex) { WriteError($"atomic write 실패: {ex.Message}"); return 2; }
356	
357	        // 결정적 test seam — atomic replace 직후 실패 주입 (production 노출 플래그 아님).
358	        var seamFail = Environment.GetEnvironmentVariable("_ST_SEAM_FAIL_AFTER_WRITE") == "1"
359	            ? "test seam: _ST_SEAM_FAIL_AFTER_WRITE" : null;
360	        if (seamFail is not null)
361	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, seamFail, canonicalMode);
362	
363	        // Step 9: 적용후 검사.
364	        // canonical mode에서만 projection 실행(--root 사본에서 projection을 실행하면 실 저장소를 덮어쓴다).
365	        if (canonicalMode)
366	        {
367	            var projExit = ProjectionCli.Run(["projection"]);
368	            if (projExit != 0)
369	                return Rollback(workstatePath, logPath, preimage, preimageHash, envelope, "projection-failed", true);
370	        }
371	
372	        // 내부 checker — PendingTransitionId로 pending 면제 경로를 실증한다.
373	        ReconciliationResult reconAfter;
374	        try { reconAfter = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath, envelope.TransitionId)); }
375	        catch (Exception ex)
376	        {
377	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
378	                $"post-apply checker 실행 실패: {ex.Message}", canonicalMode);
379	        }
380	
381	        if (reconAfter.Failures.Count > 0 || reconAfter.HarnessErrors.Count > 0)
382	        {
383	            var codes = string.Join("; ", reconAfter.Failures.Concat(reconAfter.HarnessErrors).Select(f => f.Code));
384	            return Rollback(workstatePath, logPath, preimage, preimageHash, envelope,
385	                $"post-apply-integrity-failed: {codes}", canonicalMode);
386	        }
387	
388	        // Step 10: v2 log append — 성공 경로에서만.
389	        string newSha;
390	        try { newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false))); }
391	        catch (Exception ex) { WriteError($"적용 후 hash 계산 실패: {ex.Message}"); return 2; }
392	
393	        var logContractHash = ComputeContractHash(
394	            envelope.TransitionId, envelope.TransitionKind, envelope.RequestSha256,
395	            envelope.ExpectedPreStateSha256, newSha, envelope.EffectiveAt);
396	        try
397	        {
398	            AppendApplierLogV2(logPath, envelope.TransitionId, "ok", 0, envelope.TransitionKind,
399	                envelope.RequestSha256, envelope.ExpectedPreStateSha256, newSha, logContractHash, envelope.EffectiveAt);
400	        }
401	        catch (Exception logEx)
402	        {
403	            Console.Error.WriteLine(new JsonObject
404	            {
405	                ["fatal"] = "AUDIT_LOG_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
406	                ["detail"] = $"v2 log append threw: {logEx.Message} — 다음 전이 금지, log 수동 검증 필요",
407	            }.ToJsonString());
408	            return 2;
409	        }
410	
411	        Console.WriteLine(new JsonObject
412	        {
413	            ["ok"] = true, ["transitionId"] = envelope.TransitionId,
414	            ["previousStatus"] = workstate["status"]?.ToString(),
415	            ["newStatus"] = recomputedCandidate["status"]?.ToString(),
416	            ["workstateSha256"] = newSha,
417	            ["pendingExemptionUsed"] = reconAfter.Metrics?.PendingExemptionApplied,
418	        }.ToJsonString(WriteOptions));
419	        return 0;
420	    }
421	
422	    // rollback: preimage를 복원하고 FATAL taxonomy에 따라 exit code와 로그를 결정한다.
423	    private static int Rollback(
424	        string workstatePath, string logPath, byte[] preimage, string preimageHash,
425	        EnvelopeData envelope, string failureReason, bool canonicalMode)
426	    {
427	        try
428	        {
429	            File.WriteAllBytes(workstatePath, preimage);
430	            var restoredStr = File.ReadAllText(workstatePath, new UTF8Encoding(false));
431	            var restoredHash = ComputeSha256(restoredStr);
432	
433	            if (!string.Equals(restoredHash, preimageHash, StringComparison.OrdinalIgnoreCase))
434	            {
435	                // 복원 후 hash 불일치 — FATAL.
436	                AppendLogSafe(logPath, envelope.TransitionId, "FATAL_STATE_UNKNOWN", 2);
437	                Console.Error.WriteLine(new JsonObject
438	                {
439	                    ["fatal"] = "FATAL_STATE_UNKNOWN", ["transitionId"] = envelope.TransitionId,
440	                    ["detail"] = "preimage 복원 hash 불일치 — 모든 자동작업 중단. HUMAN-INBOX 필요.",
441	                }.ToJsonString());
442	                return 2;
443	            }
444	
445	            // canonical mode에서만 rollback 후 projection 재생성 시도.
446	            if (canonicalMode)
447	            {
448	                var projExit = ProjectionCli.Run(["projection"]);
449	                if (projExit != 0)
450	                {
451	                    AppendLogSafe(logPath, envelope.TransitionId, "STATE_RESTORED_PROJECTION_NOT_VERIFIED", 2);
452	                    Console.Error.WriteLine(new JsonObject
453	                    {
454	                        ["fatal"] = "STATE_RESTORED_PROJECTION_NOT_VERIFIED",
455	                        ["transitionId"] = envelope.TransitionId,
