486	    // RunLegacy: 이전 단일-샷 방식(--transition-id 등). reconciliation이 추가됐다.
487	    private static int RunLegacy(string[] args)
488	    {
489	        var opts = ParseLegacyArgs(args);
490	        if (opts is null)
491	        {
492	            Console.Error.WriteLine("{\"error\":\"--transition-id, --expected-workstate-sha256, --request 가 모두 필요합니다\"}");
493	            return 2;
494	        }
495	        try
496	        {
497	            var root = string.IsNullOrWhiteSpace(opts.Root) ? GitTools.FindRepoRoot() : opts.Root;
498	            var workstatePath = Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
499	            if (!File.Exists(workstatePath)) { WriteError("WORKSTATE.json not found"); return 2; }
500	
501	            var raw = File.ReadAllText(workstatePath, new UTF8Encoding(false));
502	            var workstate = JsonNode.Parse(raw)?.AsObject();
503	            if (workstate is null) { WriteError("WORKSTATE.json is not a valid JSON object"); return 2; }
504	
505	            // Step 1: 낙관적 동시성 — sha256 불일치 시 쓰지 않는다.
506	            var currentSha = ComputeSha256(raw);
507	            if (!string.Equals(currentSha, opts.ExpectedSha256, StringComparison.OrdinalIgnoreCase))
508	                return Fail(1, opts.TransitionId, "sha256-mismatch",
509	                    $"expected={Short(opts.ExpectedSha256)} actual={Short(currentSha)}");
510	
511	            var logPath = Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
512	
513	            // Step 2: reconciliation — idempotency보다 먼저 실행해 가짜 id 공격을 막는다.
514	            var reconResult = HandoffIntegrityChecker.Run(new ReconciliationOptions(workstatePath, logPath));
515	            if (reconResult.Failures.Count > 0 || reconResult.HarnessErrors.Count > 0)
516	            {
517	                var codes = string.Join("; ", reconResult.Failures.Concat(reconResult.HarnessErrors).Select(f => f.Code));
518	                return Fail(1, opts.TransitionId, "state-corrupted-preapply", codes);
519	            }
520	
521	            // Step 3: 멱등 판정 (reconciliation 통과 후).
522	            if (IsAlreadyAppliedWithLog(workstate, reconResult, opts.TransitionId, out var legacyIdempotentExit))
523	                return legacyIdempotentExit;
524	
525	            var actualRoot = string.IsNullOrWhiteSpace(opts.Root) ? GitTools.FindRepoRoot() : root;
526	            return ApplyLegacy(workstatePath, logPath, workstate, opts, actualRoot);
527	        }
528	        catch (Exception ex)
529	        {
530	            Console.Error.WriteLine($"{{\"error\":\"state-transition 실패: {ex.Message}\"}}");
531	            return 2;
532	        }
533	    }
