535	    // ApplyLegacy: 이전 단일-샷 경로의 검증·쓰기·post-apply를 실행한다.
536	    private static int ApplyLegacy(
537	        string workstatePath, string logPath, JsonObject workstate,
538	        LegacyOptions opts, string actualRoot)
539	    {
540	        if (!File.Exists(opts.RequestPath)) { WriteError($"request file not found: {opts.RequestPath}"); return 2; }
541	        var request = JsonNode.Parse(File.ReadAllText(opts.RequestPath))?.AsObject();
542	        if (request is null) { WriteError("request JSON은 JSON 객체여야 한다"); return 2; }
543	
544	        var validErr = ValidateRequest(request, opts, workstate, actualRoot);
545	        if (validErr is not null) return Fail(1, opts.TransitionId, "validation-failed", validErr);
546	
547	        var effectiveAt = DateTime.UtcNow.ToString("o");
548	        var candidate = BuildCandidate(workstate, request, opts.TransitionId, effectiveAt);
549	
550	        if (opts.DryRun) return ApplyLegacyDryRun(workstate, candidate, opts, actualRoot);
551	
552	        var tmpPath = workstatePath + ".stateapplier.tmp";
553	        var candidateJson = candidate.ToJsonString(WriteOptions);
554	        File.WriteAllText(tmpPath, candidateJson, new UTF8Encoding(false));
555	
556	        var candidateCheck = JsonNode.Parse(File.ReadAllText(tmpPath))?.AsObject();
557	        var recheckErr = candidateCheck is null ? "임시 파일 파싱 실패" : ValidateCandidate(candidateCheck, actualRoot);
558	        if (recheckErr is not null) { File.Delete(tmpPath); return Fail(1, opts.TransitionId, "candidate-invalid", recheckErr); }
559	
560	        File.Move(tmpPath, workstatePath, overwrite: true);
561	
562	        // canonical mode에서만 post-apply 실행.
563	        if (string.IsNullOrWhiteSpace(opts.Root))
564	        {
565	            var postExit = RunLegacyPostApply(logPath, opts);
566	            if (postExit != 0) return postExit;
567	        }
568	
569	        var newSha = ComputeSha256(File.ReadAllText(workstatePath, new UTF8Encoding(false)));
570	        AppendApplierLog(logPath, opts.TransitionId, "ok", 0);
571	        Console.WriteLine(new JsonObject
572	        {
573	            ["ok"] = true,
574	            ["transitionId"] = opts.TransitionId,
575	            ["previousStatus"] = workstate["status"]?.ToString(),
576	            ["newStatus"] = candidate["status"]?.ToString(),
577	            ["workstateSha256"] = newSha,
578	        }.ToJsonString(WriteOptions));
579	        return 0;
580	    }
