617	    // envelope JSON을 읽어 EnvelopeData로 파싱한다. 실패 시 null 반환.
618	    private static EnvelopeData? ReadEnvelope(string envelopePath)
619	    {
620	        if (!File.Exists(envelopePath)) { WriteError($"envelope file not found: {envelopePath}"); return null; }
621	        JsonObject env;
622	        try
623	        {
624	            env = JsonNode.Parse(File.ReadAllText(envelopePath, new UTF8Encoding(false)))?.AsObject()
625	                ?? throw new InvalidOperationException("envelope is not a JSON object");
626	        }
627	        catch (Exception ex) { WriteError($"envelope parse 실패: {ex.Message}"); return null; }
628	
629	        var kind = env["transitionKind"]?.GetValue<string>() ?? "NORMAL";
630	        var tid = env["transitionId"]?.GetValue<string>() ?? "";
631	        if (string.IsNullOrWhiteSpace(tid)) { WriteError("envelope.transitionId missing"); return null; }
632	
633	        var preHash = env["expectedPreStateSha256"]?.GetValue<string>() ?? "";
634	        var reqPath = env["requestPath"]?.GetValue<string>() ?? "";
635	        var reqSha = env["requestSha256"]?.GetValue<string>() ?? "";
636	        var effAt = env["effectiveAt"]?.GetValue<string>() ?? "";
637	        var postHash = env["expectedPostStateSha256"]?.GetValue<string>() ?? "";
638	        var candidatePath = env["candidatePath"]?.GetValue<string>() ?? "";
639	        var contractSha = env["transitionContractSha256"]?.GetValue<string>();
640	
641	        if (string.IsNullOrWhiteSpace(preHash) || string.IsNullOrWhiteSpace(reqPath) ||
642	            string.IsNullOrWhiteSpace(reqSha) || string.IsNullOrWhiteSpace(effAt) ||
643	            string.IsNullOrWhiteSpace(postHash) || string.IsNullOrWhiteSpace(candidatePath))
644	        {
645	            WriteError("envelope 필수 필드 누락 (transitionId/expectedPreStateSha256/requestPath/requestSha256/effectiveAt/expectedPostStateSha256/candidatePath)");
646	            return null;
647	        }
648	
649	        var sv = env["schemaVersion"]?.GetValue<int>() ?? 1;
650	        return new EnvelopeData(sv, kind, tid, preHash, reqPath, reqSha, effAt, postHash, contractSha, candidatePath);
651	    }
