653	    // 전이 ID가 이미 state에 있는지 판정하고 idempotent/collision/legacy-unverifiable exit를 반환한다.
654	    private static int? CheckExistingTransition(
655	        JsonObject workstate, ReconciliationResult reconResult, EnvelopeData envelope)
656	    {
657	        var isInState = workstate["appliedTransitions"] is JsonArray applied &&
658	            applied.OfType<JsonObject>().Any(o =>
659	                string.Equals(o["id"]?.ToString(), envelope.TransitionId, StringComparison.Ordinal));
660	
661	        if (!isInState) return null; // 미적용 — 정상 경로로 진행.
662	
663	        // state에 있음 — log 조회.
664	        reconResult.SuccessLookup.TryGetValue(envelope.TransitionId, out var logInfo);
665	        if (logInfo is null || !logInfo.Exists)
666	        {
667	            // reconciliation이 PASS했으므로 state+log 불일치는 없어야 함 — 방어 코드.
668	            return Fail(1, envelope.TransitionId, "state-corrupted-preapply",
669	                $"id '{envelope.TransitionId}' in state but not in success log");
670	        }
671	
672	        if (logInfo.SchemaVersion < 2 || string.IsNullOrWhiteSpace(logInfo.TransitionContractSha256))
673	        {
674	            // v1 log — 내용 결속 검증 불가.
675	            return Fail(1, envelope.TransitionId, "legacy-idempotency-unverifiable",
676	                $"id '{envelope.TransitionId}'는 v1 log에 있음 — contract binding 검증 불가");
677	        }
678	
679	        // v2 log — envelope의 contract hash와 비교.
680	        // envelope에 contractHash가 있으면 직접 비교, 없으면 계산.
681	        var envelopeContractHash = string.IsNullOrWhiteSpace(envelope.TransitionContractSha256)
682	            ? null : envelope.TransitionContractSha256;
683	
684	        if (envelopeContractHash is null || !string.Equals(
685	            envelopeContractHash, logInfo.TransitionContractSha256, StringComparison.OrdinalIgnoreCase))
686	        {
687	            return Fail(1, envelope.TransitionId, "transition-id-collision",
688	                $"id '{envelope.TransitionId}'는 다른 contract hash로 이미 적용됨");
689	        }
690	
691	        // 동일 contract hash — idempotent.
692	        return ReportIdempotent(envelope.TransitionId);
693	    }
