695	    // 이전 단일-샷 경로의 멱등 판정. v2 log 항목이면 legacy-unverifiable, v1이면 idempotent.
696	    private static bool IsAlreadyAppliedWithLog(
697	        JsonObject workstate, ReconciliationResult reconResult, string transitionId, out int exitCode)
698	    {
699	        var applied = workstate["appliedTransitions"] as JsonArray;
700	        if (applied is null || !applied.OfType<JsonObject>().Any(o =>
701	            string.Equals(o["id"]?.ToString(), transitionId, StringComparison.OrdinalIgnoreCase)))
702	        {
703	            exitCode = 0;
704	            return false;
705	        }
706	
707	        reconResult.SuccessLookup.TryGetValue(transitionId, out var logInfo);
708	        if (logInfo?.SchemaVersion >= 2)
709	        {
710	            exitCode = Fail(1, transitionId, "legacy-idempotency-unverifiable",
711	                $"id '{transitionId}'는 v2 log에 있음 — legacy 경로에서 재적용 불가");
712	            return true;
713	        }
714	        exitCode = ReportIdempotent(transitionId);
715	        return true;
716	    }
