718	    // effectiveAt을 외부에서 받아 결정적 candidate를 구성한다. UtcNow 호출 없음.
719	    private static JsonObject BuildCandidate(
720	        JsonObject current, JsonObject request, string transitionId, string effectiveAt)
721	    {
722	        var candidate = JsonNode.Parse(current.ToJsonString(WriteOptions))!.AsObject()!;
723	
724	        foreach (var key in new[] { "phaseId", "wpId", "diId", "status", "blockers", "nextActions", "updatedBy", "notes" })
725	        {
726	            if (request[key] is JsonNode node)
727	                candidate[key] = node.DeepClone();
728	        }
729	
730	        // updatedAt은 effectiveAt의 날짜 부분으로 결정한다 — UtcNow 호출 없음.
731	        if (DateTimeOffset.TryParse(effectiveAt, null, DateTimeStyles.RoundtripKind, out var ea))
732	            candidate["updatedAt"] = ea.ToString("yyyy-MM-dd");
733	
734	        if (candidate["appliedTransitions"] is not JsonArray applied)
735	        {
736	            applied = new JsonArray();
737	            candidate["appliedTransitions"] = applied;
738	        }
739	
740	        applied.Add(new JsonObject
741	        {
742	            ["id"] = transitionId,
743	            ["appliedAt"] = effectiveAt,
744	        });
745	
746	        return candidate;
747	    }
