749	    // apply 경로용 request 검증 — human-decision 플래그 없이 동작한다.
750	    private static string? ValidateRequestForApply(
751	        JsonObject request, EnvelopeData envelope, JsonObject current, string root)
752	    {
753	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
754	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
755	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
756	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
757	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
758	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
759	
760	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
761	        if (!ValidStatuses.Contains(newStatus))
762	            return $"status '{newStatus}'는 허용 목록에 없습니다";
763	
764	        var currentStatus = current["status"]?.ToString() ?? "";
765	        var currentDiId = current["diId"]?.ToString() ?? "";
766	        var requestDiId = request["diId"]?.ToString();
767	
768	        // apply 경로에서 human-decision 없이 전이 그래프를 검증한다.
769	        var transErr = ValidateStatusTransition(currentStatus, newStatus, currentDiId, requestDiId, null);
770	        if (transErr is not null) return transErr;
771	
772	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
773	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
774	
775	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
776	            return "status=blocked인데 blockers가 비어있습니다";
777	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
778	            return $"status={newStatus}인데 nextActions가 비어있습니다";
779	
780	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
781	        {
782	            var targetDiId = requestDiId ?? currentDiId;
783	            var wsUpdatedAt = current["updatedAt"]?.ToString() ?? "";
784	            var verdictErr = ValidateVerdict(null, targetDiId, wsUpdatedAt);
785	            if (verdictErr is not null) return verdictErr;
786	        }
787	
788	        var curPhase = current["phaseId"]?.ToString();
789	        var newPhase = request["phaseId"]?.ToString();
790	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
791	            return $"Phase 전이({curPhase} → {newPhase})는 transitionKind=PHASE_CHANGE를 사용하세요 (이번 WP fail-closed)";
792	
793	        if (!string.IsNullOrWhiteSpace(root))
794	        {
795	            var wpId = request["wpId"]?.ToString() ?? current["wpId"]?.ToString();
796	            if (!string.IsNullOrWhiteSpace(wpId))
797	            {
798	                var regErr = ValidateWpRegistry(root, wpId);
799	                if (regErr is not null) return regErr;
800	            }
801	        }
802	        return null;
803	    }
