805	    // request JSON의 canonical ID 패턴, status enum, DI 경계·전이 그래프·verdict·human-decision을 검증한다.
806	    private static string? ValidateRequest(JsonObject request, LegacyOptions opts, JsonObject current, string root)
807	    {
808	        if (request["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
809	            return $"phaseId '{ph}'는 canonical 형식(P00, P01 …)이 아닙니다";
810	        if (request["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
811	            return $"wpId '{wp}'는 canonical 형식(WP-00 …)이 아닙니다";
812	        if (request["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
813	            return $"diId '{di}'는 canonical 형식(DI-00-05 …)이 아닙니다";
814	
815	        var newStatus = request["status"]?.ToString() ?? current["status"]?.ToString() ?? "";
816	        if (!ValidStatuses.Contains(newStatus))
817	            return $"status '{newStatus}'는 허용 목록(waiting|in_progress|verifying|completed|blocked)에 없습니다";
818	
819	        var currentStatus = current["status"]?.ToString() ?? "";
820	        var currentDiId = current["diId"]?.ToString() ?? "";
821	        var requestDiId = request["diId"]?.ToString();
822	
823	        var transErr = ValidateStatusTransition(currentStatus, newStatus, currentDiId, requestDiId,
824	            opts.HumanDecisionPath);
825	        if (transErr is not null) return transErr;
826	
827	        var newBlockers = request["blockers"] as JsonArray ?? current["blockers"] as JsonArray ?? new JsonArray();
828	        var newNext = request["nextActions"] as JsonArray ?? current["nextActions"] as JsonArray ?? new JsonArray();
829	
830	        if (string.Equals(newStatus, "blocked", StringComparison.OrdinalIgnoreCase) && newBlockers.Count == 0)
831	            return "status=blocked인데 blockers가 비어있습니다";
832	        if (NextActionsRequired.Contains(newStatus) && newNext.Count == 0)
833	            return $"status={newStatus}인데 nextActions가 비어있습니다 — 독립 재개가 실패하는 지점입니다";
834	
835	        if (string.Equals(newStatus, "completed", StringComparison.OrdinalIgnoreCase))
836	        {
837	            var targetDiId = requestDiId ?? currentDiId;
838	            var wsUpdatedAt = current["updatedAt"]?.ToString() ?? "";
839	            var verdictErr = ValidateVerdict(opts.VerdictPath, targetDiId, wsUpdatedAt);
840	            if (verdictErr is not null) return verdictErr;
841	        }
842	
843	        var curPhase = current["phaseId"]?.ToString();
844	        var newPhase = request["phaseId"]?.ToString();
845	        if (newPhase is not null && !string.Equals(newPhase, curPhase, StringComparison.OrdinalIgnoreCase))
846	        {
847	            var gateErr = ValidateHumanDecision(opts.HumanDecisionPath, $"Phase 전이({curPhase} → {newPhase})");
848	            if (gateErr is not null) return gateErr;
849	        }
850	
851	        return null;
852	    }
