854	    // DI 경계와 전이 그래프를 검사한다.
855	    private static string? ValidateStatusTransition(
856	        string currentStatus, string newStatus, string currentDiId, string? requestDiId,
857	        string? humanDecisionPath)
858	    {
859	        var isNewDi = requestDiId is not null &&
860	                      !string.Equals(requestDiId, currentDiId, StringComparison.OrdinalIgnoreCase);
861	
862	        if (isNewDi)
863	        {
864	            if (!string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
865	                return $"새 DI 착수({currentDiId} → {requestDiId})는 현재 DI가 completed여야 합니다(현재: {currentStatus})";
866	            if (!string.Equals(newStatus, "waiting", StringComparison.OrdinalIgnoreCase) &&
867	                !string.Equals(newStatus, "in_progress", StringComparison.OrdinalIgnoreCase))
868	                return $"새 DI 착수 시 status는 waiting 또는 in_progress만 허용합니다(요청: {newStatus})";
869	            return null;
870	        }
871	
872	        if (string.Equals(currentStatus, newStatus, StringComparison.OrdinalIgnoreCase)) return null;
873	
874	        // completed는 terminal — 이탈하려면 human-decision 필요 (legacy 경로).
875	        if (string.Equals(currentStatus, "completed", StringComparison.OrdinalIgnoreCase))
876	            return ValidateHumanDecision(humanDecisionPath, $"completed 상태 전이({currentStatus} → {newStatus})");
877	
878	        if (AllowedTransitions.TryGetValue(currentStatus, out var allowed) && !allowed.Contains(newStatus))
879	        {
880	            var allowedStr = allowed.Count > 0 ? string.Join(", ", allowed) : "없음(terminal)";
881	            return $"status 전이 {currentStatus} → {newStatus}는 허용되지 않습니다(허용: {allowedStr})";
882	        }
883	        return null;
884	    }
