886	    // gate.json 형식·gateVerdict·failureCount·taskId 일치·stale 여부를 검증한다.
887	    private static string? ValidateVerdict(string? verdictPath, string targetDiId, string workstateUpdatedAt)
888	    {
889	        if (string.IsNullOrWhiteSpace(verdictPath))
890	            return "status=completed 전이에는 --verdict 파일이 필요합니다";
891	
892	        var normalized = verdictPath.Replace('\\', '/');
893	        var fileName = Path.GetFileName(normalized);
894	        if (!fileName.EndsWith(".gate.json", StringComparison.OrdinalIgnoreCase))
895	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
896	
897	        var dirPart = Path.GetDirectoryName(normalized)?.Replace('\\', '/') ?? "";
898	        if (!dirPart.EndsWith("outputs/gates", StringComparison.OrdinalIgnoreCase))
899	            return $"verdict 경로는 outputs/gates/<taskId>.gate.json 형식이어야 합니다(받음: {verdictPath})";
900	
901	        if (!File.Exists(verdictPath)) return $"verdict file not found: {verdictPath}";
902	
903	        var gateJson = JsonNode.Parse(File.ReadAllText(verdictPath))?.AsObject();
904	        if (gateJson is null) return "gate JSON이 유효하지 않습니다";
905	
906	        var gateVerdict = gateJson["gateVerdict"]?.ToString();
907	        if (!string.Equals(gateVerdict, "PASS", StringComparison.OrdinalIgnoreCase))
908	            return $"gate verdict가 PASS가 아닙니다(gateVerdict={gateVerdict ?? "null"})";
909	
910	        var failureCount = gateJson["failureCount"]?.GetValue<int>() ?? -1;
911	        if (failureCount != 0) return $"gate failureCount가 0이 아닙니다(failureCount={failureCount})";
912	
913	        var gateTaskId = gateJson["taskId"]?.ToString();
914	        if (!string.Equals(gateTaskId, targetDiId, StringComparison.OrdinalIgnoreCase))
915	            return $"gate taskId({gateTaskId ?? "null"})가 전이 대상 DI({targetDiId})와 일치하지 않습니다";
916	
917	        var createdAtStr = gateJson["createdAt"]?.ToString();
918	        if (createdAtStr is not null &&
919	            DateTimeOffset.TryParse(createdAtStr, out var createdAt) &&
920	            DateTime.TryParse(workstateUpdatedAt, out var wsUpdated) &&
921	            createdAt.Date < wsUpdated.Date)
922	        {
923	            return $"gate 증거가 WORKSTATE updatedAt({workstateUpdatedAt})보다 오래됐습니다(gate createdAt={createdAt:yyyy-MM-dd})";
924	        }
925	        return null;
926	    }
