928	    // human-decision 파일이 approved=true인지 검증한다. 골격 유지 — 이 경로는 이번 WP에서 fail-closed다.
929	    private static string? ValidateHumanDecision(string? decPath, string context)
930	    {
931	        if (string.IsNullOrWhiteSpace(decPath))
932	            return $"{context}에는 --human-decision 파일이 필요합니다";
933	        if (!File.Exists(decPath)) return $"human-decision file not found: {decPath}";
934	        var d = JsonNode.Parse(File.ReadAllText(decPath))?.AsObject();
935	        if (d is null) return "human-decision JSON이 유효하지 않습니다";
936	        var approved = d["approved"]?.GetValue<bool>() ?? false;
937	        return !approved ? $"{context}가 사람에게 승인되지 않았습니다(approved={approved})" : null;
