944	        if (!ValidStatuses.Contains(status)) return $"candidate status '{status}'가 유효하지 않습니다";
945	
946	        var blockers = candidate["blockers"] as JsonArray;
947	        if (string.Equals(status, "blocked", StringComparison.OrdinalIgnoreCase) && (blockers is null || blockers.Count == 0))
948	            return "candidate: status=blocked인데 blockers가 비어있습니다";
949	
950	        var nextActions = candidate["nextActions"] as JsonArray;
951	        if (NextActionsRequired.Contains(status) && (nextActions is null || nextActions.Count == 0))
952	            return $"candidate: status={status}인데 nextActions가 비어있습니다";
953	
954	        if (candidate["phaseId"] is JsonNode ph && !Regex.IsMatch(ph.ToString(), @"^P\d{2,}$"))
955	            return $"candidate phaseId '{ph}'는 canonical 형식이 아닙니다";
956	        if (candidate["wpId"] is JsonNode wp && !Regex.IsMatch(wp.ToString(), @"^WP-\d{2,}$"))
957	            return $"candidate wpId '{wp}'는 canonical 형식이 아닙니다";
958	        if (candidate["diId"] is JsonNode di && !Regex.IsMatch(di.ToString(), @"^DI-\d{2}-\d{2,}$"))
959	            return $"candidate diId '{di}'는 canonical 형식이 아닙니다";
960	
961	        var wpId = candidate["wpId"]?.ToString();
962	        if (!string.IsNullOrWhiteSpace(wpId))
963	        {
964	            var registryErr = ValidateWpRegistry(root, wpId);
965	            if (registryErr is not null) return registryErr;
966	        }
967	        return null;
